import sys
import heapq

def main():
    input = sys.stdin.read
    data = input().split()

    N = int(data[0])
    M = int(data[1])
    X = int(data[2])

    original_adj = [[] for _ in range(N + 1)]
    reversed_adj = [[] for _ in range(N + 1)]

    index = 3
    for _ in range(M):
        u = int(data[index])
        v = int(data[index + 1])
        original_adj[u].append(v)
        reversed_adj[v].append(u)
        index += 2

    INF = float('inf')
    dist_normal = [INF] * (N + 1)
    dist_reversed = [INF] * (N + 1)

    dist_normal[1] = 0

    heap = []
    heapq.heappush(heap, (0, 1, False))

    while heap:
        cost, node, is_reversed = heapq.heappop(heap)

        if node == N:
            print(cost)
            return

        if is_reversed:
            if cost > dist_reversed[node]:
                continue
        else:
            if cost > dist_normal[node]:
                continue

        # Movement
        if not is_reversed:
            for neighbor in original_adj[node]:
                new_cost = cost + 1
                if new_cost < dist_normal[neighbor]:
                    dist_normal[neighbor] = new_cost
                    heapq.heappush(heap, (new_cost, neighbor, False))
        else:
            for neighbor in reversed_adj[node]:
                new_cost = cost + 1
                if new_cost < dist_reversed[neighbor]:
                    dist_reversed[neighbor] = new_cost
                    heapq.heappush(heap, (new_cost, neighbor, True))

        # Reverse operation
        if not is_reversed:
            new_cost = cost + X
            if new_cost < dist_reversed[node]:
                dist_reversed[node] = new_cost
                heapq.heappush(heap, (new_cost, node, True))
        else:
            new_cost = cost + X
            if new_cost < dist_normal[node]:
                dist_normal[node] = new_cost
                heapq.heappush(heap, (new_cost, node, False))

    print(min(dist_normal[N], dist_reversed[N]))

if __name__ == "__main__":
    main()
